A life-cycle hook that provides a higher order promise that does not resolve if component un-mounts.

## Usage

```tsx


const Demo = () => {
  const mounted = useUnmountPromise();
  useEffect(async () => {
    await mounted(someFunction()); // Will not resolve if component un-mounts.
  });
};
```

## Type Declarations

```ts
type Race = <P extends Promise<any>, E = any>(
  promise: P,
  onError?: (error: E) => void
) => P;

declare const useUnmountPromise: () => Race;
```

> **Credit:** Re-export from [react-use]()

React effect hook that ignores the first invocation (e.g. on mount). The signature is exactly the same as the `useEffect` hook.

## Usage

```tsx



const Demo = () => {
  const [count, setCount] = React.useState(0);

  useEffect(() => {
    const interval = setInterval(() => {
      setCount((count) => count + 1);
    }, 1000);

    return () => {
      clearInterval(interval);
    };
  }, []);

  useUpdateEffect(() => {
    console.log("count", count); // will only show 1 and beyond

    return () => {
      // *OPTIONAL*
      // do something on unmount
    };
  }); // you can include deps array if necessary

  return <view>Count: {count}</view>;
};
```

## Type Declarations

```ts


declare const useUpdateEffect: typeof useEffect;
```

A Hook for exposing imperative handles to parent components on the main-thread. This is the main-thread version of
React's [useImperativeHandle](), allowing you to trigger component methods that run on the main-thread.

## Usage

```tsx




interface InternalCompMTRef {
  start: () => void;
}

function InternalComp({
  "main-thread:ref": MTRef,
}: {
  "main-thread:ref"?: MainThreadRef<InternalCompMTRef | null>;
}) {
  function start() {
    "main thread";
    console.log("MT Start");
  }

  useMainThreadImperativeHandle(
    MTRef,
    () => {
      "main thread";
      return {
        start: start,
      };
    },
    []
  );

  return (
    <view>
      <text>Internal Comp</text>
    </view>
  );
}

function App() {
  const internalMTRef = useMainThreadRef<InternalCompMTRef>(null);

  return (
    <view>
      <InternalComp main-thread:ref={internalMTRef} />
      <view
        main-thread:bindtap={() => {
          "main thread";
          internalMTRef.current?.start();
        }}
      >
        <text>Click to Trigger</text>
      </view>
    </view>
  );
}
```

## Type Declarations

```ts


function useMainThreadImperativeHandle<T, R extends T>(
  ref: MainThreadRef<T> | undefined,
  createHandle: () => R,
  deps: readonly unknown[]
): void;
```

A Hook unifies [`TouchEvent`]() and [`MouseEvent`]() into `PointerEvent`, to help with handling pointer events in a cross-platform manner.

## Usage

```tsx


function App() {
  const pointerHandlers = usePointerEvent({
    onPointerDown: (event: CustomPointerEvent) => {
      console.log("Pointer down", event);
    },
    onPointerDownMT: (event: CustomPointerEventMT) => {
      'main thread'
      console.log("Pointer down on main thread", event);
    },
  });

  return <view {...pointerHandlers}></view>
}

```

## Type Declarations

```tsx
type PointerAction = 'pointerdown' | 'pointermove' | 'pointerup';

interface CustomPointerEvent {
    type: PointerAction;
    pointerType: 'mouse' | 'touch';
    x: number;
    y: number;
    pointerId: number;
    isPrimary: boolean;
    pageX?: number;
    pageY?: number;
    clientX?: number;
    clientY?: number;
    button?: number;
    buttons?: number;
    identifier?: number;
    originalEvent: unknown;
}

interface CustomPointerEventMT extends CustomPointerEvent {
    target: MainThread.Element;
    currentTarget: MainThread.Element;
    originalEvent: MainThread.MouseEvent | MainThread.TouchEvent;
}

function usePointerEvent({ onPointerDown, onPointerUp, onPointerMove, onPointerUpMT, onPointerMoveMT, onPointerDownMT, }: {
    onPointerDown?: (event: CustomPointerEvent) => void;
    onPointerUp?: (event: CustomPointerEvent) => void;
    onPointerMove?: (event: CustomPointerEvent) => void;
    onPointerUpMT?: (event: CustomPointerEventMT) => void;
    onPointerMoveMT?: (event: CustomPointerEventMT) => void;
    onPointerDownMT?: (event: CustomPointerEventMT) => void;
}): {
    'bindmousedown'?: (e: MouseEvent) => void;
    'bindtouchstart'?: (e: TouchEvent) => void;
    'bindmousemove'?: (e: MouseEvent) => void;
    'bindtouchmove'?: (e: TouchEvent) => void;
    'bindmouseup'?: (e: MouseEvent) => void;
    'bindtouchend'?: (e: TouchEvent) => void;
    'main-thread:bindmousedown'?: (e: MainThread.MouseEvent) => void;
    'main-thread:bindtouchstart'?: (e: MainThread.TouchEvent) => void;
    'main-thread:bindmousemove'?: (e: MainThread.MouseEvent) => void;
    'main-thread:bindtouchmove'?: (e: MainThread.TouchEvent) => void;
    'main-thread:bindmouseup'?: (e: MainThread.MouseEvent) => void;
    'main-thread:bindtouchend'?: (e: MainThread.TouchEvent) => void;
};

```

A Hook for locking tap events when tap movement exceeds a specified threshold in a given direction.

## Usage

```tsx


function Demo() {
  const { tapLockRef, handleTouchStart, handleTouchMove, handleTouchEnd } =
    useTapLock();

  const handleTap = () => {
    if (tapLockRef.current) {
      console.log("Tap allowed");
    } else {
      console.log("Tap locked due to movement");
    }
  };

  return (
    <view
      main-thread:bindtouchstart={handleTouchStart}
      main-thread:bindtouchmove={handleTouchMove}
      main-thread:bindtouchend={handleTouchEnd}
      bindtap={handleTap}
    >
      Tap me
    </view>
  );
}
```

## Type Declarations

```ts


type TapLockDirection = 'x' | 'y' | 'both';

interface UseTapLockOptions {
  /**
   * Movement threshold in pixels
   * @default 8
   */
  tapThreshold?: number;

  /**
   * Direction to monitor
   * @default 'x'
   */
  direction?: TapLockDirection;
}

function useTapLock(options?: UseTapLockOptions): {
  tapLockRef: import("@lynx-js/react").MainThreadRef<boolean>;
  handleTouchStart: (event: MainThread.TouchEvent) => void;
  handleTouchMove: (event: MainThread.TouchEvent) => boolean;
  handleTouchEnd: (event: MainThread.TouchEvent) => boolean;
};
```

A Hook synthesizes [`TouchEvent`]() from [`MouseEvent`](), so existing touch handlers can work seamlessly with mouse input. Useful for migration from touch-only code.

## Usage

```tsx


function App() {
  const touchHandlers = useTouchEmulation({
    onTouchStart: (event: TouchEvent) => {
      console.log("Touch start", event);
    },
    onTouchStartMT: (event: MainThread.TouchEvent) => {
      'main thread'
      console.log("Touch start on main thread", event);
    },
  });

  return <view {...touchHandlers}></view>
}
```

