React state hook implements simple FIFO queue.

## Usage

```tsx


const Demo = () => {
  const { add, remove, first, last, size } = useQueue();

  return (
    <view>
      <view>
        <text>first: {first}</text>
      </view>
      <view>
        <text>last: {last}</text>
      </view>
      <view>
        <text>size: {size}</text>
      </view>
      <view bindtap={() => add((last || 0) + 1)}>Add</view>
      <view bindtap={() => remove()}>Remove</view>
    </view>
  );
};
```

